scwin.sbm_retrieveCertiWhole_submitDone = function (e) {
  // 날짜열 데이터 조합
  for (i = 0; i < ds_certiCommon.getTotalRow(); i++) {
    let strDt = ds_certiCommon.getCellData(i, "qryConDtFm");
    let endDt = ds_certiCommon.getCellData(i, "qryConDtTo");
    let Dt = strDt + endDt;
    ds_certiCommon.setCellData(i, "Dt", Dt);
  }
};

