//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  // inObj가 코드명 필드일 경우 팝업
  else scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 품목, 품명, 화종 코드 팝업 구분
//-------------------------------------------------------------------------
scwin.f_beforeOpenCommonPopUp = function (arg, cd, nm) {
  if (arg == "txt") {
    if (acb_qryConKnd.getValue() == "품목") {
      scwin.f_chkOpenCommonPopUp(nm, cd, 3, false);
    } else if (lc_qryConKnd.BindColVal == "품명") {
      scwin.f_chkOpenCommonPopUp(nm, cd, 4, false);
    } else {
      scwin.f_chkOpenCommonPopUp(nm, cd, 5, false);
    }
  } else {
    if (acb_qryConKnd.getValue() == "품목") {
      scwin.f_openCommonPopUp(3, cd.getValue(), nm.getValue(), 'F', 'F');
    } else if (acb_qryConKnd.getValue() == "품명") {
      scwin.f_openCommonPopUp(4, cd.getValue(), nm.getValue(), 'F', 'F');
    } else {
      scwin.f_openCommonPopUp(5, cd.getValue(), nm.getValue(), 'F', 'F');
    }
  }
};

//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList = new Array(); // 공통POP-UP -> 요청화면 

  switch (disGubun) {
    case 1:
      //청구부서코드팝업			
      udc_bilgLodept.cfCommonPopUp(scwin.udc_bilgLodept_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 2:
      //청구화주코드팝업			
      udc_bilgClnt.cfCommonPopUp(scwin.udc_bilgClnt_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 3:
      // 품목코드 팝업			
      udc_qryCon.setSelectId("retrieveCommInfo");
      udc_qryCon.cfCommonPopUp(scwin.udc_qryCon_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, ',,3', null, null, null, null, null, pAllSearch, '품목,품목코드,품목');
      break;
    case 4:
      udc_qryCon.setSelectId("retrieveCommInfo");
      // 품명코드 팝업			
      udc_qryCon.cfCommonPopUp(scwin.udc_qryCon_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, ',,4', null, null, null, null, null, pAllSearch, '품명,품명코드,품명');
      break;
    case 5:
      udc_qryCon.setSelectId("retrieveKcgInfo");
      // 화종코드 팝업			
      udc_qryCon.cfCommonPopUp(scwin.udc_qryCon_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, '1', null, null, null, null, null, pAllSearch, null);
      break;
    default:
      break;
  }
};

