//-------------------------------------------------------------------------
// 건별조회 Cell 클릭시
//-------------------------------------------------------------------------
scwin.f_certiNoDetail = async function () {
  let row = gr_certiCommon.getFocusedRowIndex();
  let pgmId = ds_certiCommon.getCellData(row, "pgmId");
  if (pgmId == "fs_202_06_04p.jsp") {
    pgmId = "fs_202_04_01b.jsp";
  }
  pgmId = pgmId.replace(".jsp", ".xml");
  let strCertiNoDetailUrl = "/ui/ds/fs/bilg/" + pgmId;

  // 선택된 certiNo 정보 : bilgLodeptCd , certiNo
  let v_bilgLodeptCd = ds_certiCommon.getCellData(row, "bilgLodeptCd");
  let v_certiNo = ds_certiCommon.getCellData(row, "certiNo");
  let v_link = "true";

  //팝업 옵션 설정
  let options = {
    id: "taxPop",
    type: "",
    popupName: "",
    width: 1100,
    height: 650
  };

  //팝업 화면에 데이터 보내는 방법 1. json형태로 팝업화면에서 getParameter로 받기
  let args = {
    bilgLodeptCd: v_bilgLodeptCd,
    certiNo: v_certiNo,
    link: v_link
  };
  if (pgmId == "fs_202_04_01b.xml") {
    options.popupName = "수출입 거래명세서 작성";
  } else if (pgmId == "fs_202_04_03b.xml") {
    options.popupName = "기간매출 거래명세서 작성";
  } else if (pgmId == "fs_202_04_06b.xml") {
    options.popupName = "내수 거래명세서 작성";
  } else if (pgmId == "fs_202_05_01b.xml") {
    options.popupName = "컨테이너별 CERTI 생성";
  } else if (pgmId == "fs_202_05_03b.xml") {
    options.popupName = "CERTI 생성";
  } else if (pgmId == "fs_202_05_05b.xml") {
    options.popupName = "기간매출 CERTI 생성";
  }

  //menuNm, url, pgmId, paramObj, option
  //상세화면 호출
  $c.win.openMenu($p, options.popupName, strCertiNoDetailUrl, pgmId, args, options);
  return;
};

